.budget-preview {
  position: relative;
  background-color: var(--color-panel-background);
  border-radius: 10px;

  &__title {
    display: flex;
    gap: 11px;

    h2 {
      font-size: 16px;
      font-weight: 400;
      cursor: pointer;
    }

    svg {
      color: var(--color-gray-2);
    }
  }

  &__details {
    display: flex;
    // justify-content: space-between;
    align-items: center;
    gap: 20px;
  }

  &__detail {
    display: grid;
    width: 90px;

    & > .budget-preview__label {
      font-size: 12px;
      font-weight: 400;
      color: var(--color-gray-2);
      margin-bottom: 2px;
    }

    & > .budget-preview__value {
      font-size: 16px;
      line-height: calc(1em * var(--line-height-ratio-small));
      font-weight: 600;
    }
  }

  &__shared {
    display: flex;
    gap: 12px;
    align-items: center;
    font-size: 12px;
  }

  @media (width < 60rem) {
    padding: 18px 16px;

    &__details {
      margin-top: 18px;
    }

    &__info {
      padding-bottom: 0;
    }
  }

  @media (width >= 60rem) {
    padding: 12px 23px 15px 19px;

    &__info {
      display: flex;
      justify-content: space-between;
      padding: 0 1px 0 5px;
    }

    &__title {
      padding-top: 8px;
    }

    &__detail {
      text-align: right;
    }

    &__footer {
      display: flex;
      justify-content: space-between;
      margin-block-start: 11px;
      padding-inline: 5px 1px;
    }
  }
}

// User

.budget-user {
  position: relative;
  padding-inline-start: 30px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: var(--color-gray-transparent);
  font-weight: 500;
  white-space: nowrap;

  img {
    position: absolute;
    inset-block-start: 50%;
    inset-inline-start: 0;
    translate: 0 -50%;
    width: 24px;
    height: 24px;
    background: var(--color-gray-1);
    border-radius: 50%;
  }
}

.budget-users {
  font-size: 12px;
  font-weight: 500;
}

