.au-button {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 42px;
  border: none;
  border-radius: 10px;
  padding: 0 22px;
  color: var(--color-white);
  font-size: 16px;
  line-height: calc(1em * var(--line-height-ratio));
  font-weight: 600;
  transition: background-color 0.3s ease;
  cursor: pointer;
  white-space: nowrap;

  &--primary {
    background-color: var(--color-primary-blue);

    &:hover {
      background-color: var(--color-primary-blue-darker);
    }

    &:active {
      background-color: var(--color-primary-blue-dark);
    }
  }

  &--secondary {
    background-color: var(--color-primary-green);

    &:hover {
      background-color: var(--color-primary-green-darker);
    }

    &:active {
      background-color: var(--color-primary-green-dark);
    }
  }

  &--transparent {
    background-color: var(--color-primary-blue-light);
    color: var(--color-primary-blue);

    &:hover {
      background-color: var(--color-primary-blue-lighter);
    }

    &:active {
      background-color: var(--color-primary-blue-transparent);
    }
  }

  &--delete {
    color: var(--color-error-red);
  }

  &--icon {
    background-color: var(--color-primary-blue-light);
    color: var(--color-primary-blue);
    width: 38px;
    height: 38px;
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0;

    &.au-button--small {
      width: 28px;
      height: 28px;
    }

    &:hover {
      background-color: var(--color-primary-blue-lighter);
    }

    &:active {
      background-color: var(--color-primary-blue-transparent);
    }

    &.au-button--medium {
      min-width: unset;
      width: 42px;
      height: 42px;
    }
  }

  &--link {
    width: fit-content;
    height: fit-content;
    border: none;
    background-color: transparent;
    color: var(--color-primary-blue);
    font-size: 14px;
    line-height: 1.2em;
    font-weight: 600;
    padding: 0;

    &:hover {
      color: var(--color-primary-blue-darker);
    }

    &:active {
      color: var(--color-primary-blue-dark);
    }

    &.au-button--medium {
      min-width: unset;
      width: 42px;
      height: 42px;
    }
  }

  &--chips {
    border: 1px solid var(--color-primary-blue-transparent);
    height: 32px;
    font-size: 12px;
    border-radius: 16px;
    color: var(--color-primary-blue-transparent);
    background-color: var(--color-white);

    &:hover {
      color: var(--color-white);
      background-color: var(--color-primary-blue);
    }

    &:active {
      color: var(--color-primary-blue);
      background-color: var(--color-primary-blue-transparent);
    }

    &[aria-pressed='true'] {
      color: var(--color-white);
      background-color: var(--color-primary-blue);
    }
  }

  &--medium {
    min-width: 209px;
  }

  &--large {
    width: 100%;
    min-width: 255px;
    height: 50px;
  }

  &--small {
    padding: 0;
    font-size: 12px;
    font-weight: 700;
  }
}

