file.content:
html {
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  background-color: var(--color-background);
  color: var(--color-text);

  @media (width < 60rem) {
    &.modal-open {
      overflow: hidden;
    }
  }
}

#root {
  display: flex;
  position: relative;
  min-height: 100dvh;
  justify-content: center;
}

// breadcrumb

.breadcrumb {
  padding: 3px 8px 2px;

  a {
    font-weight: 600;
  }
}

// Footer

.footer {
  width: 100%;
  padding: 22px;
  background: var(--color-foreground);
  border-radius: 20px 20px 0 0;
}

.footer__logo {
  width: 131px;
  height: 36px;
  margin: auto;
  background-color: var(--color-border);
  border-radius: 6px;
}

// Chips

.chips {
  padding-block-end: 16px;
  overflow: auto;
  scrollbar-width: none;

  &::-webkit-scrollbar {
    display: none;
    width: 0;
    background: transparent;
  }

  @media (width < 60rem) {
    width: 100vw;
    margin-inline: -16px;
    padding-inline: 16px;
  }
}

.chips-list {
  display: flex;
  gap: 8px;
  width: 100%;
}

