:root {
  color-scheme: light;

  --color-primary-blue-dark: #002468;
  --color-primary-blue-darker: #0640ac;
  --color-primary-blue-transparent: rgb(7 94 255 / 50%);
  --color-primary-blue: #075eff;
  --color-primary-blue-lighter: #c3d7ff;
  --color-primary-blue-lighter-transparent: rgb(195 215 255 / 50%);
  --color-primary-blue-light: #f3f7ff;

  --color-primary-green-dark: #044e1d;
  --color-primary-green-darker: #007025;
  --color-primary-green: #00aa39;

  --color-gray-1: #616161;
  --color-gray-transparent: rgb(164 166 172 / 50%);
  --color-gray-2: #a4a6ac;
  --color-gray-3: #ced2da;
  --color-gray-4: #e7e9ef;

  --color-error-red: #e30008;
  --color-error-red-transparent: rgb(227 0 8 / 50%);

  --color-notify-orange: #ed6b00;

  --color-black: #8b8787;
  --color-white: #ffffff;

  --line-height-ratio: 1.55;
  --line-height-ratio-small: 1.2;
  --line-height-ratio-medium: 1.3;

  --width-desktop: 1232px;
  --width-mobile: 320px;
  --width-current: clamp(var(--width-mobile), 100%, var(--width-desktop));

  // Semantic colors WIP
  --color-background: var(--color-primary-blue-light);
  --color-foreground: #fff;
  --color-border: var(--color-gray-4);
  --color-text: #000;
  --color-link: var(--color-primary-blue);
  --color-link-hover: var(--color-primary-blue-darker);

  --color-panel-background: var(--color-primary-blue-light);

  --color-input-background: var(--color-foreground);
  --color-input-border: var(--color-gray-2);
  --color-input-border-hover: var(--color-primary-blue-transparent);
  --color-input-border-active: var(--color-primary-blue);
}

@media (prefers-color-scheme: dark) {
  //:root {
  .none {
    color-scheme: dark;

    --color-background: #000;
    --color-foreground: #1f2023;
    --color-border: #303236;
    --color-text: #fff;
    --color-link: #7eabff;
    --color-link-hover: var(--color-primary-blue-light);

    --color-panel-background: #242528;

    --color-input-border: var(--color-gray-1);
  }
}

