.budget-group {
  display: grid;

  &__header {
    width: fit-content;
    height: 24px;
    display: flex;
    align-items: center;
    gap: 4px;
    font-size: 16px;
    font-weight: 600;
    line-height: 1.5;

    .budget-group__name {
      cursor: grabbing;
    }
  }

  &__footer {
    display: flex;
    justify-content: flex-end;
    padding: 12px 24px 12px 17px;
    border-top: 1px solid var(--color-gray-4);
  }

  .budget-group__edit-button {
    background-color: var(--color-white);
    color: var(--color-gray-2);

    &:hover {
      background-color: var(--color-primary-blue-lighter);
    }
  }

  @media (width < 60rem) {
    gap: 10px;

    &__footer {
      justify-content: flex-start;
      border: none;
    }
  }

  @media (width >= 60rem) {
    gap: 8px;

    &__footer {
      gap: 20px;
    }
  }
}

