file.content:
.transaction-info {
  display: flex;
  flex-direction: column;
  width: 100%;

  hr {
    border-color: var(--color-border);
    border-top: 1px;
    margin: 15px 0;
  }

  &__header {
    display: flex;
    justify-content: space-between;
    margin-bottom: 15px;

    &-actions {
      display: flex;
      gap: 10px;
    }

    & > h3 {
      display: flex;
      align-items: center;
    }
  }

  &__price {
    &-currency {
      color: var(--color-text-subtle);
      font-weight: 400;
      font-size: 16px;
      text-transform: uppercase;
      line-height: 1.5;
      letter-spacing: 0;
      margin-bottom: 4px;
    }

    &-amount {
      font-size: 32px;
      font-weight: 600;
      line-height: var(--line-height-ratio-small);
    }
  }

  &__merchant-block {
    padding: 4px 0 16px;
    border-bottom: 1px solid var(--color-border);
    margin-bottom: 16px;
  }

  &__merchant-name {
    color: var(--color-text-muted);
    font-size: 16px;
    line-height: var(--line-height-ratio-small);
    font-weight: 600;
    line-height: 1.3;
  }

  &__account-name {
    color: var(--color-text-subtle);
    font-size: 14px;
    line-height: var(--line-height-ratio-small);
  }

  &__details {
    font-size: 16px;
    margin-bottom: 16px;

    &-row {
      display: flex;
      align-items: flex-start;
      margin-bottom: 4px;
    }

    &-label {
      font-weight: 600;
      margin: 0 10px 0 0;
    }

    &-value {
      display: flex;
      flex: 1;
      flex-wrap: wrap;
      font-weight: 400;
    }

    &__details-row--location {
      flex-direction: column;

      & dt {
        margin-bottom: 4px;
      }

      & dd {
        width: 100%;
      }
    }
  }

  &__map {
    width: 100%;
    height: 200px;
    margin-top: 4px;
    border-radius: 16px;
    background-color: var(--color-gray-5);
    overflow: hidden;
  }

  &__footer {
    margin-top: 16px;
    display: flex;
    flex-direction: column;
    gap: 8px;
    padding-top: 16px;
  }

  &__action-btn {
    width: 100%;
    justify-content: center;
    gap: 8px;
  }
}

