&__map {
  width: 100%;
  height: 200px;
  margin-top: 4px;
  border-radius: 16px;
  background-color: var(--color-gray-5);
  overflow: hidden;
}

input.new_string:
&__map {
  width: 100%;
  height: 200px;
  margin-top: 4px;
  border-radius: 16px;
  background-color: var(--color-disabled-bg);
  overflow: hidden;
}

